import axios from 'axios';

const API_BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:8000/api/v1';

export interface Listing {
  id: number;
  external_id: string;
  title: string;
  description: string;
  location: string;
  bedrooms: number;
  bathrooms: number;
  area_sqft: number;
  price_history: PriceHistory[];
  created_at: string;
  updated_at: string;
}

export interface PriceHistory {
  price: number;
  recorded_at: string;
}

export interface PriceTrend {
  date: string;
  avg_price: number;
}

export interface ListingsFilter {
  location?: string;
  min_price?: number;
  max_price?: number;
  bedrooms?: number;
  skip?: number;
  limit?: number;
}

const api = {
  async getListings(filters: ListingsFilter = {}): Promise<Listing[]> {
    const response = await axios.get(`${API_BASE_URL}/listings`, { params: filters });
    return response.data;
  },

  async getListing(id: number): Promise<Listing> {
    const response = await axios.get(`${API_BASE_URL}/listings/${id}`);
    return response.data;
  },

  async getPriceTrends(location?: string, days: number = 30): Promise<PriceTrend[]> {
    const response = await axios.get(`${API_BASE_URL}/price-trends`, {
      params: { location, days }
    });
    return response.data;
  }
};

export default api;
